import{_ as n,o,c as t,ae as a}from"./chunks/framework.BMBGeRFM.js";const p=JSON.parse('{"title":"Changing Conventions","description":"","frontmatter":{"title":"Changing Conventions","date":"2026-04-18T00:00:00.000Z"},"headers":[],"relativePath":"news/2026-04-18-conventions.md","filePath":"news/2026-04-18-conventions.md"}'),i={name:"news/2026-04-18-conventions.md"};function r(s,e,c,h,d,l){return o(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="version-prefix-change" tabindex="-1">Version Prefix Change! <a class="header-anchor" href="#version-prefix-change" aria-label="Permalink to &quot;Version Prefix Change!&quot;">​</a></h1><p>It seems that unnecessarily changing conventions and stuff is becoming the norm across tech with everything now becoming CalVer after 10 years of being SemVer, or basically the same thing but with phones, systems, etc. (not pointing out anybody here, but you know who..)</p><p>...and Farben&#39;s jumping right on top of that hype train! I&#39;m planning on changing how the members&#39; versions are being referenced! It&#39;s not as bad as changing version numbering convention anyway.</p><p>Right now they use the classic old <code>v</code> prefix. From now on, the version prefix will be changed across crates:</p><ul><li>farben: <code>frb*</code>, or just <code>v*</code> if there&#39;s no <code>frb*</code></li><li>farben-core: <code>core*</code></li><li>farben-macros: <code>macros*</code></li><li>farben-build: <code>build*</code></li><li>farben-md: <code>md*</code></li></ul><p>Why am I changing them? I&#39;m not sure. It&#39;s just better to look at the versions in a glance and know which crates they represent instead of having to put their whole name in front of it (farben-macros 0.x.y vs macros0.x.y).</p><p>This wouldn&#39;t change anything about Farben itself, just how I&#39;ll represent the versions in future CHANGELOG entries or these news headers. Make great things with Farben!</p><p>Cheers, RazkarStudio</p>',8)])])}const f=n(i,[["render",r]]);export{p as __pageData,f as default};
